SELECT version_name, release_date
FROM replicant_versions
WHERE is_active = 1;

SELECT COUNT(*) AS active_versions_count
FROM replicant_versions
WHERE is_active = 1;

SELECT COUNT(contribution_id) AS contribution_count
FROM user_contributions
WHERE user_id = 0;

SELECT device_model, device_screen_resolution
FROM supported_devices
WHERE is_supported = 1;

SELECT COUNT(device_id) AS supported_device_count
FROM supported_devices
WHERE version_id = 0;
